import sys

class Solution:
    def minCut(self, s: str) -> int:
        n = len(s)
        dp = [False] * n
        palin = [[False] * n for _ in range(n)]
        for i in range(n - 1, -1, -1):
            dp[i] = n - i - 1
            for j in range(i, n):
                if s[i] == s[j] and (j - i < 2 or palin[i + 1][j - 1]):
                    palin[i][j] = True
                    if j == n - 1:
                        dp[i] = 0
                    elif dp[i] > dp[j + 1] + 1:
                        dp[i] = dp[j + 1] + 1
        return dp[0]

