#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minCut(string s) {
        int n = s.size();
        vector<bool> dp(n);
        vector<vector<bool>> palin(n, vector<bool>(n));
        for (int i = n - 1; i >= 0; --i) {
            dp[i] = n - i - 1;
            for (int j = i; j < n; ++j) {
                if (s[i] == s[j] && (j - i < 2 || palin[i + 1][j - 1])) {
                    palin[i][j] = true;
                    if (j == n - 1) {
                        dp[i] = 0;
                    } else if (dp[i] > dp[j + 1] + 1) {
                        dp[i] = dp[j + 1] + 1;
                    }
                }
            }
        }
        return dp[0];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string s;
    cin.ignore();
    getline(cin, s);
    Solution sol;
    int ans = sol.minCut(s);
    cout << ans << '\n';
    return 0;
}
